// Per-circuit lube status dots (worst-of the 3 signals)
// ============================================================
function levelOfRaw(b, vv) {
  // mirror of threshold logic in JS form for any binding spec inline
  return ''; // unused stub
}
function rankOf(v, warn, crit, dir) {
  if (v === null || v === undefined || isNaN(v)) return 0;
  if (dir === 'high') {
    if (v > crit) return 3;
    if (v >= warn) return 2;
    return 1;
  } else {
    if (v < crit) return 3;
    if (v <= warn) return 2;
    return 1;
  }
}
function rankToColor(r) {
  return r === 3 ? COLOR.critical : r === 2 ? COLOR.warning : r === 1 ? COLOR.normal : COLOR.nodata;
}

[
  {cid:'fan_de'},  {cid:'fan_nde'}, {cid:'mot_de'}, {cid:'mot_nde'}
].forEach(function(c){
  var rFlow  = rankOf(values['lube_'+c.cid+'_flow'],  30,  20,  'low');
  var rPress = rankOf(values['lube_'+c.cid+'_press'], 1.5, 1.0, 'low');
  var rTemp  = rankOf(values['lube_'+c.cid+'_temp'],  65,  75,  'high');
  var worst = Math.max(rFlow, rPress, rTemp);
  setAttr('lube_'+c.cid+'_status_dot', 'fill', rankToColor(worst));
});

