// Asset health rollup (top right KPI)
// ============================================================
(function(){
  var live = counts.normal + counts.warning + counts.critical;
  var total = 31;
  var pctNormal = live > 0 ? Math.round((counts.normal / live) * 100) : 0;
  setText('health_value', pctNormal + '%');
  setText('health_summary_text',
    counts.normal + ' normal · ' + counts.warning + ' warn · ' + counts.critical + ' crit');
  var hv = svgnode.getElementById('health_value');
  if (hv) {
    if      (counts.critical > 0) hv.setAttribute('fill', COLOR.critical);
    else if (counts.warning  > 0) hv.setAttribute('fill', COLOR.warning);
    else if (counts.nodata   === total) hv.setAttribute('fill', COLOR.nodata);
    else                          hv.setAttribute('fill', COLOR.normal);
  }
  setText('health_status_text',
    counts.critical > 0 ? 'CRITICAL — investigate' :
    counts.warning  > 0 ? 'WARNING' :
    live === 0          ? 'NO DATA' :
                          'NORMAL');
})();

// ============================================================
// Rotor rotation — rotation rate proportional to WGF_SPEED
// Marcus Calidus events re-run on every refresh. We keep angle
// in a global-ish variable on svgnode so it survives across runs.
// ============================================================
(function(){
  var speed = values['wgf_speed'];
  // Persist angle on svgnode
  if (typeof svgnode.__rotorAngle === 'undefined') svgnode.__rotorAngle = 0;
  if (typeof svgnode.__rotorTimer !== 'undefined') {
    try { clearInterval(svgnode.__rotorTimer); } catch(e) {}
    svgnode.__rotorTimer = undefined;
  }
  if (speed === null || speed === undefined || isNaN(speed) || speed <= 0) {
    return;  // no rotation
  }
  // Scale: 800 rpm => ~12 deg/frame at 30 fps. Cap so it stays visible.
  var degPerFrame = Math.min(20, Math.max(0.5, speed / 80));
  svgnode.__rotorTimer = setInterval(function(){
    svgnode.__rotorAngle = (svgnode.__rotorAngle + degPerFrame) % 360;
    var rotor = svgnode.getElementById('fan_rotor');
    if (rotor) {
      // Preserve translate, replace rotate
      var t = rotor.getAttribute('transform') || '';
      var m = t.match(/translate\(([^)]+)\)/);
      var tr = m ? m[0] : '';
      rotor.setAttribute('transform', tr + ' rotate(' + svgnode.__rotorAngle.toFixed(1) + ')');
    }
  }, 33);
})();

